const Web3 = require('web3');
require('dotenv').config();

// Set up web3 provider
const web3 = new Web3(process.env.INFURA_URL || 'https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID');

// Load wallet with private key (NEVER expose this in production)
const privateKey = process.env.PRIVATE_KEY;
const account = web3.eth.accounts.privateKeyToAccount(privateKey);
web3.eth.defaultAccount = account.address;

async function sendEth(toAddress, amount) {
    const gasPrice = await web3.eth.getGasPrice();
    const gasLimit = 21000; // For simple transactions
    const value = web3.utils.toWei(amount.toString(), 'ether');

    const transaction = {
        to: toAddress,
        from: account.address,
        value: value,
        gas: gasLimit,
        gasPrice: gasPrice
    };

    try {
        const signedTransaction = await web3.eth.accounts.signTransaction(transaction, privateKey);
        const receipt = await web3.eth.sendSignedTransaction(signedTransaction.rawTransaction);
        console.log('Transaction receipt:', receipt);
        return receipt;
    } catch (error) {
        console.error('Error sending transaction:', error);
        throw error;
    }
}

async function interactWithContract(contractAddress, abi, functionName, ...functionArgs) {
    const contract = new web3.eth.Contract(abi, contractAddress);

    // Check if the function is a write operation
    const methodABI = abi.find(method => method.name === functionName && !method.constant);
    if (methodABI) {
        // It's a write operation, need to sign and send a transaction
        const gasPrice = await web3.eth.getGasPrice();
        const data = contract.methods[functionName](...functionArgs).encodeABI();

        const transaction = {
            from: account.address,
            to: contractAddress,
            data: data,
            gas: 100000, // Adjust gas limit as needed
            gasPrice: gasPrice
        };

        try {
            const signedTransaction = await web3.eth.accounts.signTransaction(transaction, privateKey);
            const receipt = await web3.eth.sendSignedTransaction(signedTransaction.rawTransaction);
            console.log('Contract interaction receipt:', receipt);
            return receipt;
        } catch (error) {
            console.error('Error interacting with contract:', error);
            throw error;
        }
    } else {
        // It's a read operation, can call directly
        try {
            const result = await contract.methods[functionName](...functionArgs).call();
            console.log('Contract interaction result:', result);
            return result;
        } catch (error) {
            console.error('Error interacting with contract:', error);
            throw error;
        }
    }
}

